import os, csv, re
import numpy as np

base = '/home/mrsar/protein-ag/disease-relevant non-inhibited_clean'

def find_data_files(base):
    files = []
    for root, dirs, fnames in os.walk(base):
        if 'data.tsv' in fnames:
            files.append(os.path.join(root, 'data.tsv'))
    return sorted(files)

files = find_data_files(base)
print(f'Total data.tsv files: {len(files)}')
for f in files:
    rel = f.replace(base+'/', '')
    with open(f) as fh:
        reader = csv.reader(fh, delimiter='\t')
        header = next(reader)
        rows = [r for r in reader if r]
    # count X/Y pairs
    pairs = 0
    m0_vals = []
    M0_vals = []
    for i in range(len(header)-1):
        xh = header[i]; yh = header[i+1]
        if xh.strip().endswith('X') and yh.strip().endswith('Y'):
            pairs += 1
            m = re.search(r'm0:\s*([-+]?\d+(?:\.\d+)?(?:[eE][-+]?\d+)?)', xh)
            M = re.search(r'M0:\s*([-+]?\d+(?:\.\d+)?(?:[eE][-+]?\d+)?)', xh)
            if m: m0_vals.append(float(m.group(1)))
            if M: M0_vals.append(float(M.group(1)))
    print(f'  {rel}: {pairs} curves, m0={m0_vals[:3]}, M0={M0_vals[:3]}')
